<body>
    <div class="container">
        <div class="sidebar">
            <div class="sidebar-header">
                <img src="https://icon2.cleanpng.com/lnd/20250117/ak/82e7b644f0bc410356c4657ff6d819.webp" 
                     alt="Petronas Logo" 
                     class="petronas-logo"
                     onerror="this.style.display='none'">
                <h1>📊 Dashboard</h1>
            </div>
            <p>Financial Performance Analysis</p>

            <button class="nav-button active" data-view="comparison">
                <span class="nav-icon">🔄</span>
                <span>Compare All Companies</span>
            </button>

            ${companiesData.map((company, index) => `
            <button class="nav-button" data-view="${company.id}">
                <span class="nav-icon">${company.icon}</span>
                <span>${company.name.split(' ').slice(0, 2).join(' ')}</span>
            </button>
            `).join('')}
        </div>

        <div class="main-content">
            <div id="content-area"></div>
        </div>
    </div>

    <script>
        const companiesData = ${JSON.stringify(companiesData)};
        let currentCharts = [];

        // Animated counter function
        function animateValue(element, start, end, duration, isPercentage = false, isCurrency = false) {
            const startTime = performance.now();
            const difference = end - start;

            function updateValue(currentTime) {
                const elapsed = currentTime - startTime;
                const progress = Math.min(elapsed / duration, 1);

                // Easing function for smooth animation
                const easeOutQuart = 1 - Math.pow(1 - progress, 4);
                const current = start + (difference * easeOutQuart);

                if (isCurrency) {
                    element.textContent = formatCurrency(Math.round(current));
                } else if (isPercentage) {
                    element.textContent = current.toFixed(2) + '%';
                } else {
                    element.textContent = formatNumber(Math.round(current));
                }

                if (progress < 1) {
                    requestAnimationFrame(updateValue);
                }
            }

            requestAnimationFrame(updateValue);
        }

        // Animate all numbers in view
        function animateNumbers() {
            setTimeout(() => {
                document.querySelectorAll('.kpi-value').forEach((element, index) => {
                    const text = element.textContent;
                    const isCurrency = text.includes('RM');
                    const isPercentage = text.includes('%');

                    let value = parseFloat(text.replace(/[^0-9.-]/g, ''));

                    setTimeout(() => {
                        animateValue(element, 0, value, 1500, isPercentage, isCurrency);
                    }, index * 100);
                });

                document.querySelectorAll('.metric-item .value').forEach((element, index) => {
                    const text = element.textContent;
                    const isPercentage = text.includes('%');
                    const isCurrency = text.includes('RM');

                    let value = parseFloat(text.replace(/[^0-9.-]/g, ''));

                    setTimeout(() => {
                        animateValue(element, 0, value, 1200, isPercentage, isCurrency);
                    }, index * 80);
                });
            }, 200);
        }

        function calculateRatios(data) {
            return {
                grossProfitMarginCurrent: (data.grossProfitCurrent / data.revenueCurrent * 100).toFixed(2),
                grossProfitMarginPrior: (data.grossProfitPrior / data.revenuePrior * 100).toFixed(2),
                netProfitMarginCurrent: (data.netProfitCurrent / data.revenueCurrent * 100).toFixed(2),
                netProfitMarginPrior: (data.netProfitPrior / data.revenuePrior * 100).toFixed(2),
                revenueGrowth: ((data.revenueCurrent - data.revenuePrior) / data.revenuePrior * 100).toFixed(2),
                grossProfitGrowth: ((data.grossProfitCurrent - data.grossProfitPrior) / data.grossProfitPrior * 100).toFixed(2),
                netProfitGrowth: ((data.netProfitCurrent - data.netProfitPrior) / data.netProfitPrior * 100).toFixed(2)
            };
        }

        function formatNumber(num) {
            return num.toString().replace(/\\B(?=(\\d{3})+(?!\\d))/g, ",");
        }

        function formatCurrency(num) {
            return 'RM ' + formatNumber(Math.round(num)) + 'K';
        }

        // Destroy existing charts before creating new ones
        function destroyCharts() {
            currentCharts.forEach(chart => {
                if (chart) chart.destroy();
            });
            currentCharts = [];
        }

        function renderComparisonView() {
            destroyCharts();

            const totalRevenueCurrent = companiesData.reduce((sum, c) => sum + c.data.revenueCurrent, 0);
            const totalNetProfitCurrent = companiesData.reduce((sum, c) => sum + c.data.netProfitCurrent, 0);
            const avgRevenueGrowth = (companiesData.reduce((sum, c) => sum + parseFloat(calculateRatios(c.data).revenueGrowth), 0) / companiesData.length).toFixed(2);
            const avgGrossMargin = (companiesData.reduce((sum, c) => sum + parseFloat(calculateRatios(c.data).grossProfitMarginCurrent), 0) / companiesData.length).toFixed(2);

            const html = \`
                <div class="header">
                    <h2>🏆 Multi-Company Financial Comparison</h2>
                    <p class="subtitle">Comprehensive analysis of retail industry leaders</p>
                </div>

                <div class="kpi-grid">
                    <div class="kpi-card revenue">
                        <div class="kpi-label">Total Revenue (Current)</div>
                        <div class="kpi-value">\${formatCurrency(totalRevenueCurrent)}</div>
                        <div class="kpi-change positive">Combined market value</div>
                    </div>

                    <div class="kpi-card profit">
                        <div class="kpi-label">Total Net Profit (Current)</div>
                        <div class="kpi-value">\${formatCurrency(totalNetProfitCurrent)}</div>
                        <div class="kpi-change positive">Industry performance</div>
                    </div>

                    <div class="kpi-card growth">
                        <div class="kpi-label">Average Revenue Growth</div>
                        <div class="kpi-value">\${avgRevenueGrowth}%</div>
                        <div class="kpi-change positive">Year-over-year</div>
                    </div>

                    <div class="kpi-card margin">
                        <div class="kpi-label">Average Gross Margin</div>
                        <div class="kpi-value">\${avgGrossMargin}%</div>
                        <div class="kpi-change">Profitability metric</div>
                    </div>
                </div>

                <div class="charts-grid">
                    <div class="chart-container full-width">
                        <h3 class="chart-title">📊 Revenue Comparison - Current vs Prior Period</h3>
                        <div class="chart-wrapper">
                            <canvas id="revenueComparisonChart"></canvas>
                        </div>
                    </div>

                    <div class="chart-container">
                        <h3 class="chart-title">💰 Net Profit Analysis</h3>
                        <div class="chart-wrapper">
                            <canvas id="netProfitChart"></canvas>
                        </div>
                    </div>

                    <div class="chart-container">
                        <h3 class="chart-title">📈 Growth Rate Comparison</h3>
                        <div class="chart-wrapper">
                            <canvas id="growthRateChart"></canvas>
                        </div>
                    </div>

                    <div class="chart-container">
                        <h3 class="chart-title">🎯 Gross Profit Margin</h3>
                        <div class="chart-wrapper">
                            <canvas id="marginChart"></canvas>
                        </div>
                    </div>

                    <div class="chart-container">
                        <h3 class="chart-title">🔄 Market Share by Revenue</h3>
                        <div class="chart-wrapper">
                            <canvas id="marketShareChart"></canvas>
                        </div>
                    </div>
                </div>

                <div class="comparison-table">
                    <h3 class="chart-title">📋 Detailed Financial Metrics Comparison</h3>
                    <table>
                        <thead>
                            <tr>
                                <th>Metric</th>
                                \${companiesData.map(c => '<th>' + c.name.split(' ')[0] + '</th>').join('')}
                                <th>Leader</th>
                            </tr>
                        </thead>
                        <tbody>
                            \${generateComparisonRows()}
                        </tbody>
                    </table>
                </div>
            \`;

            document.getElementById('content-area').innerHTML = html;
            animateNumbers();
            setTimeout(() => renderComparisonCharts(), 300);
        }

        function generateComparisonRows() {
            const metrics = [
                { label: 'Revenue (Current)', key: 'revenueCurrent', format: 'currency' },
                { label: 'Revenue Growth', calc: 'revenueGrowth', format: 'percent' },
                { label: 'Gross Profit (Current)', key: 'grossProfitCurrent', format: 'currency' },
                { label: 'Gross Profit Margin', calc: 'grossProfitMarginCurrent', format: 'percent' },
                { label: 'Net Profit (Current)', key: 'netProfitCurrent', format: 'currency' },
                { label: 'Net Profit Margin', calc: 'netProfitMarginCurrent', format: 'percent' },
                { label: 'Net Profit Growth', calc: 'netProfitGrowth', format: 'percent' }
            ];

            return metrics.map(metric => {
                const values = companiesData.map(company => {
                    const ratios = calculateRatios(company.data);
                    const value = metric.key ? company.data[metric.key] : ratios[metric.calc];
                    return { company: company.name, value: parseFloat(value) };
                });

                const maxValue = Math.max(...values.map(v => v.value));
                const leader = values.find(v => v.value === maxValue).company;

                return \`
                    <tr>
                        <td><strong>\${metric.label}</strong></td>
                        \${values.map(v => '<td>' + (metric.format === 'currency' ? formatCurrency(v.value) : v.value + '%') + '</td>').join('')}
                        <td><span class="rank-badge rank-1">🏆 \${leader.split(' ')[0]}</span></td>
                    </tr>
                \`;
            }).join('');
        }

        function renderCompanyView(companyId) {
            destroyCharts();

            const company = companiesData.find(c => c.id === companyId);
            const ratios = calculateRatios(company.data);

            const html = \`
                <div class="header">
                    <h2>\${company.icon} \${company.name}</h2>
                    <p class="subtitle">Detailed Financial Performance & Business Intelligence</p>
                </div>

                <div class="company-profile">
                    <div class="company-header">
                        <div class="company-logo">\${company.icon}</div>
                        <div class="company-info">
                            <h3>\${company.name}</h3>
                            <p class="industry">Retail & Convenience Store Industry</p>
                        </div>
                    </div>

                    <div class="metric-grid">
                        <div class="metric-item">
                            <div class="label">Revenue Growth</div>
                            <div class="value" style="color: \${parseFloat(ratios.revenueGrowth) > 0 ? '#4CAF50' : '#f44336'}">\${ratios.revenueGrowth}%</div>
                        </div>
                        <div class="metric-item">
                            <div class="label">Gross Margin</div>
                            <div class="value">\${ratios.grossProfitMarginCurrent}%</div>
                        </div>
                        <div class="metric-item">
                            <div class="label">Net Margin</div>
                            <div class="value">\${ratios.netProfitMarginCurrent}%</div>
                        </div>
                        <div class="metric-item">
                            <div class="label">Gross Profit Growth</div>
                            <div class="value" style="color: \${parseFloat(ratios.grossProfitGrowth) > 0 ? '#4CAF50' : '#f44336'}">\${ratios.grossProfitGrowth}%</div>
                        </div>
                        <div class="metric-item">
                            <div class="label">Net Profit Growth</div>
                            <div class="value" style="color: \${parseFloat(ratios.netProfitGrowth) > 0 ? '#4CAF50' : '#f44336'}">\${ratios.netProfitGrowth}%</div>
                        </div>
                        <div class="metric-item">
                            <div class="label">Current Revenue</div>
                            <div class="value" style="font-size: 16px;">\${formatCurrency(company.data.revenueCurrent)}</div>
                        </div>
                    </div>
                </div>

                <div class="kpi-grid">
                    <div class="kpi-card revenue">
                        <div class="kpi-label">Revenue (Current Period)</div>
                        <div class="kpi-value">\${formatCurrency(company.data.revenueCurrent)}</div>
                        <div class="kpi-change \${parseFloat(ratios.revenueGrowth) > 0 ? 'positive' : 'negative'}">
                            \${parseFloat(ratios.revenueGrowth) > 0 ? '▲' : '▼'} \${ratios.revenueGrowth}% vs prior period
                        </div>
                    </div>

                    <div class="kpi-card profit">
                        <div class="kpi-label">Gross Profit (Current)</div>
